var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 왜… 그런 모습으로, 타기리온의 영역에 있는 거지?","JPN":"そなたが何故……そのような姿で、タギリオンの領域にいるのだ？","ENG":"Why... are you dressed like that and in Thagirion's lair?","TWN":"你為什麼……以那副姿態，站在塔基里翁的領地？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"제가 아는 예하께선 누구보다 현명한 분이셨어요.","JPN":"私が知っている猊下は誰よりも賢明な方でした。","ENG":"The Eminence I knew was wiser than anyone else.","TWN":"主教是我認識的人當中最賢明的一位。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그런 어리석은 질문을 되풀이하는 건 어울리지 않네요.","JPN":"そんな愚かな質問を繰り返すのは似つかわしくありませんね。","ENG":"It's not like you to be repeating such a foolish question.","TWN":"反復提出如此愚蠢的問題很不像您。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"실은 이미 알고 계시지 않나요?","JPN":"もうお気づきですよね？","ENG":"In truth, don't you already know?","TWN":"其實您早就知道了不是嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"저를… 어떻게 불러야 하는지도.","JPN":"私を……どう呼ぶべきかも。","ENG":"How... you should address me?","TWN":"您也早就知道……如何稱呼我。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아니, 아니야!","JPN":"違う、違う！","ENG":"No, no!","TWN":"不不，不不！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 그런 선택을 할 리 없다!","JPN":"そなたがそのような選択をするはずがない！","ENG":"You would never choose to be like this!","TWN":"你絕不會這麼做！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"무섭게 소리를 지르시는군요.","JPN":"恐ろしく怒鳴るんですね。","ENG":"Your shouting is scaring me.","TWN":"您叫得很嚇人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그때처럼.","JPN":"あの時のように。","ENG":"Just like that time.","TWN":"就像那時一樣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아아…","JPN":"ああ……","ENG":"Ahh...","TWN":"啊啊……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아아아아아아!!!!!","JPN":"ああああああ！！","ENG":"AAAAGH!!!","TWN":"啊啊啊啊啊！！！！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"멈출 기회는 얼마든지 있었다.","JPN":"止める機会はいくらでもあった。","ENG":"There were plenty of chances to stop.","TWN":"曾經有很多機會停手。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"종말을 막겠다는 일념 하나에만 매몰되지 않았더라면…","JPN":"終末を防ぐという一念に囚われていなかったら……","ENG":"If only I had not been obsessed with the idea of preventing the end...","TWN":"要不是一心只想著阻止末日……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"나에겐 기회가 있었다.","JPN":"我には機会があったのだ。","ENG":"I had the opportunity.","TWN":"我本來還有機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 내린 선택이 그릇될 수 있다는 사실을 인정했더라면…","JPN":"我が下した決断が間違うこともあるということを認めたのならば……","ENG":"If only I had accepted that my choices could have been wrong...","TWN":"要是我承認我的選擇有可能是錯的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"…소녀가 그토록 비참한 결말을 맞지는 않았으리라.","JPN":"……あの少女があんな残酷な結末を迎えなくてもよかったのだろう。","ENG":"…the child would not have met such a tragic ending.","TWN":"……那麼她就不會落得如此悲慘的下場。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이렇게 다시 만나기만을 손꼽아 기다렸어요.","JPN":"こうして再び会えることを待ち望んでいました。","ENG":"I've been waiting patiently for the day we meet again.","TWN":"我迫不及待地想再見到您。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"예하.","JPN":"猊下。","ENG":"Your Eminence.","TWN":"主教。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"가장 행복했던 시절의 소녀가 보인다.","JPN":"一番幸せだった頃の少女が見える。","ENG":"In front of me, I see a girl when she was the happiest.","TWN":"我看到了一個她最快樂的時光。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"그녀에겐 자신의 누이가 세상의 전부였고, 숭배하는 모든 것이었다.","JPN":"彼女には自分の姉が世界の全てであり、崇拝する全てであった。","ENG":"Her sister was her whole world and everything she worshipped.","TWN":"對她來說，姊姊就是世界上的一切，是她崇拜的一切。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"엘리시움의 오만을 구원이라는 변명으로 외면했던 나의 이기심은…","JPN":"エリシウムの傲慢を救いという弁明で目を背けていた我の利己心は……","ENG":"However, my selfishness, which made me turn a blind eye to Elysium's arrogance in the name of salvation...","TWN":"我將愛樂的傲慢當作救贖的世界藉口，對我的自私視而不見……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"그 소녀의 세상을 망가뜨렸다.","JPN":"あの少女の世界を崩壊させてしまった。","ENG":"Destroyed the girl's world.","TWN":"因此毀掉她的整個世界。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"종말을 불러들이는 흉악한 인형으로 만들고 말았다.","JPN":"終末を呼び込む凶悪な人形にしてしまったのだ。","ENG":"Made her into this wicked doll that brings about the end.","TWN":"讓她變成帶來末日的邪惡魁儡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는 이미 이 세계의 그녀들을 너의 자매로 만들었다.","JPN":"そなたはすでにこの世界の少女たちをそなたの姉妹にしたのだ。","ENG":"You have already made the girls of this world into your sisters.","TWN":"你已經讓這個世界上的她們變成了你的姊妹。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 이상의 희생에 무슨 의미가 있지?","JPN":"それ以上の犠牲に何の意味があるのだ？","ENG":"What is the point of making more sacrifices beyond that?","TWN":"更多的犧牲還有什麼意義？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…희생이 아니에요.","JPN":"……犠牲でありません。","ENG":"...They aren't sacrifices.","TWN":"……並不是犧牲。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"타의와 악의에 의한 가장 비통한 죽음으로부터, 제가 조금 더 일찍 건져냈을 뿐이죠.","JPN":"他意と悪意によるもっとも残酷な死から、私が少しだけ早く救いだしただけです。","ENG":"They would've experienced death in the most painful form, by others and by evil. I've simply saved them before that.","TWN":"我只是先一步將她們從充滿惡意的悲慘死亡中救了出來而已。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 그마저도 지금은, 인간들의 이기심에 무참히 짓이겨졌어요. 그렇지 않나요?","JPN":"でもそれすら今は、人間たちの利己心によって踏みにじられました。そうでしょう？","ENG":"But even that has now been crushed by the selfishness of humans, have they not?","TWN":"但即使是這樣，現在還是被人類的自私殘暴地對待，不是嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"우리 그림자가 마땅히 설 수 있는 자리는 없으니.","JPN":"我らシャドウがまっとうに立っていられる場所はない。","ENG":"There is no place for Shadows like us.","TWN":"我們暗影無立足之處。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 자매를 위한 복수가 이 세상을 무너뜨릴 이유가 되어선 안 된다.","JPN":"姉妹のための復讐がこの世界を滅ぼす理由になってはならないのだ。","ENG":"You must not bring ruin to a world for the sake of avenging your sister.","TWN":"為你的姊妹復仇不應該成為讓這個世界毀滅的理由。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇다면 대답해보세요.","JPN":"ならば、答えてください。","ENG":"Then answer me this.","TWN":"那麼請你回答。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"세상을 위해, 저와 언니의 죽음을 그저 방관하는 것이… 아름다운 결말인지.","JPN":"世界のために私とお姉さんの死をただ見過ごすのが……美しい結末なのか。","ENG":"Was it a beautiful conclusion... to neglect the death of my sister and my deaths for the world?","TWN":"為了這個世界而對我和我姊姊的死袖手旁觀……是不是一個美麗的結局。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 그 질문에 답할 자격이 없다.","JPN":"我はその問いに答える資格がない。","ENG":"I have no right to answer that question.","TWN":"我沒有資格回答這個問題。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"차라리 나의 죽음으로 여기서 모든 복수를 끝낼 수 있다면… 나를 쳐라.","JPN":"いっそのこと、我の死をもって全ての復讐を終えることができるのならば……ここで討て。","ENG":"If your vengeance will end with my death... Then kill me.","TWN":"如果可以用我的性命來結束這場復仇戲……儘管殺我吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"알겠어요.","JPN":"わかりました。","ENG":"All right.","TWN":"好的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그럼 저항하지 말고, 얌전히 계세요.","JPN":"では抵抗せずに、大人しくしてください。","ENG":"Then stay still and don't resist.","TWN":"乖乖站著，不要抵抗。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"예하의 몸뚱아리는 그 잡초 같은 근성만큼이나 질기네요.","JPN":"猊下の体はその雑草のような根性に似てしぶといですね。","ENG":"Your body has the grit of weeds, Your Eminence.","TWN":"主教的身子如同野草一般頑強呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 핵을 깨부수면, 제 발목을 잡는 꼴을 더는 안 봐도 되겠죠.","JPN":"その核を砕けば、これ以上私の邪魔はできないでしょう。","ENG":"By crushing that core, I won't have to see you holding me back any longer.","TWN":"把那個核心破壞掉，就不能再扯我的後腿了吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이걸로 네 복수를 멈출 수 있다면… 나에게 후회는 없다.","JPN":"これでそなたの復讐が止まるのならば……我は後悔せん。","ENG":"If this will end your vengeance... I have no regrets.","TWN":"如果這能阻止你的復仇……我無怨無悔。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"복수…?","JPN":"復讐……？","ENG":"Vengeance...?","TWN":"復仇……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아하하… 아직도 제가 거짓말 한 마디 못하는 순진한 아이 같나요?","JPN":"あはは……まだ私が嘘も言えない無邪気な子どもだと思いますか？","ENG":"Ah hah hah... Do you still believe me to be the naive, innocent little girl?","TWN":"啊……你還以為我是個不會撒謊的天真孩子嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제가 당신의 죽음을 바랐던 건, 아주 오래전 일이에요.","JPN":"私があなたの死を願ったのは、大昔のことです。","ENG":"It was a long time ago when I wanted you dead.","TWN":"我希望你死已經是很久很久以前的事了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"저는 당신의 핵을 부수고… 재조립해서…","JPN":"私はあなたの核を砕き……再び組み立てて……","ENG":"But now, I'm going to break your core... then reassemble it...","TWN":"我要打碎你的核心……然後重組……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"더는 날 방해하지 못하게 만들 거예요.","JPN":"これ以上私を邪魔しないようにします。","ENG":"so you won't be able to bother me anymore.","TWN":"讓你再也不能妨礙我。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……!"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온…!","JPN":"タギリオン……！","ENG":"Thagirion...!","TWN":"塔基里翁……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는…?","JPN":"そなたは……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"현실로 돌아가요, 모르스.","JPN":"現実に戻りましょう、モールス。","ENG":"Go back to the Normalside, Mors.","TWN":"回歸現實吧，死神。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신은 아직 여기서 무너지면 안돼.","JPN":"あなたはまだここで倒れてはいけません。","ENG":"You can't be defeated just yet.","TWN":"你還不能在這裡倒下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네가… 왜 날 지키는 거지?","JPN":"そなたが……何故我を守るのか？","ENG":"Why... are you protecting me?","TWN":"你……你為什麼要保護我？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 아이에게 구원받은 뒤로, 죄업을 피해 도망친 것이 아니었나?","JPN":"あの子に救われ、罪から逃げていたのではなかったのか？","ENG":"After that child saved you, were you not running away from your sins?","TWN":"在被那孩子拯救之後，你不是一直在逃避自己的罪嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"죄인은… 자기 죄를 부정하고 외면할 수도, 인정하고 받아들일 수도 있어요.","JPN":"罪人は……自分の罪を否定し無視することも、認めて受け止めることもできます。","ENG":"Sinners... can either deny and turn away from their sins, or admit and accept it.","TWN":"罪人……可以否認和無視，也可以承認並接受自己的罪過。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 도망치는 걸론 아무것도 바꾸지 못하겠더라고요.","JPN":"でも、逃げるだけでは何も変えられないと思いました。","ENG":"But from what I've experienced, running away doesn't change anything.","TWN":"但一昧逃避卻改變不了任何東西。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"힘겹게 얻어낸 기적을 이런 식으로 헛되이 버릴 셈인가?","JPN":"苦労して手に入れた奇跡を無駄にするつもりなのか？","ENG":"Do you wish to waste your hard-earned miracle like this?","TWN":"你打算就這樣浪費得來不易的奇蹟嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내 선택이 헛된지 아닌지는… 당신한테 달려있어요.","JPN":"私の選択が無駄なのかどうかは……あなた次第です。","ENG":"Whether my choice will be a waste or not... depends on you.","TWN":"我的選擇究竟是否徒勞……取決於你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러니 돌아가요! 어서!","JPN":"だから戻って！　早く！","ENG":"So, go back! Hurry!","TWN":"所以趕快回去吧，快點！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"정말로 침입자를 쫓지 않으시는 겁니까?","JPN":"本当に侵入者を追わないのですか？","ENG":"Are you really not going to chase after the intruder?","TWN":"真的不去追那入侵者嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이미 최고단원 다수가 그 아이의 습격에 속수무책으로 당했습니다.","JPN":"すでに最高団員の多くがあの子の襲撃によってやられています。","ENG":"Many of the Elite Members have fallen to the child's attack.","TWN":"已經有許多團員因那孩子的襲擊束手無策地倒下。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"쫓아봐야 불필요한 희생만 늘어날 뿐이죠.","JPN":"追いかけたって無駄な犠牲が増えるだけです。","ENG":"Chasing after her will only create more unnecessary causalities.","TWN":"就算去追也只會發生更多無謂的犧牲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"하지만 그 때문에 저희의 연구가 누설되기라도 한다면…","JPN":"ですが、そのせいで私たちの研究が漏れてしまったら……","ENG":"But if our research were to be leaked because of her...","TWN":"但萬一我們的研究因此而洩漏……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"돌아오지 않을 거예요.","JPN":"戻らないでしょう。","ENG":"She will not be coming back.","TWN":"她不會回來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"설령 그 아이가 돌아온다고 한들, 누가 이교도의 말을 곧이곧대로 믿어 줄까요?","JPN":"たとえあの子どもが戻ったとしても、異教徒の話を信じる人はいないはずです。","ENG":"Even if she did, who would believe the words of a pagan?","TWN":"即使她真的回來了，誰會相信異教徒的話呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"…그렇겠군요. 알겠습니다, 지휘자님.","JPN":"……そうですね。わかりました、指揮者様。","ENG":"...I see. Understood, Chief Conductor.","TWN":"……我明白了，指揮家。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜 그 아이에게 마지막까지 말하지 않으셨죠?","JPN":"なぜその子どもに最後まで言わなかったの？","ENG":"Why didn't you tell the child?","TWN":"你為什麼到最後也沒告訴她？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자기 언니가 살인을 저지른 죄수라는 걸 말해줬다면, 그 아이의 억울함을 조금이나마 달랠 수 있었을 텐데요.","JPN":"自分の姉が殺人を犯した罪人であることを言ってあげれば、その子どもの無念を少しは和らげてあげられたはずなのに。","ENG":"If you had told her that her sister was a sinner who committed murder, you could have alleviated some of her grievances.","TWN":"如果她知道自己的姊姊是一個殺人犯，應該能稍微減輕她心中的委屈感。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"죄인에겐 죄인을 비난할 자격이 없습니다.","JPN":"罪人に罪人を非難する資格などありません。","ENG":"A sinner has no right to blame other sinners.","TWN":"罪人無權譴責罪人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"성흔을 지우는 독약의 대가는 흰 서리 꽃 한 떨기와 수많은 인간들의 목숨.","JPN":"聖痕の痕跡を消す毒薬の対価は一輪の白い雪の花と多くの人間の命。","ENG":"The price to pay for a concoction of removing a Stigmata is one White Frost Flower and many lives of humans.","TWN":"用毒藥消除聖痕的代價是一朵白霜花和無數人類的性命。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 여인 또한 그들의 방식대로 종말을 막기 위해, 최선을 다했을 뿐이니까요.","JPN":"その女性もまた、彼らのやり方で終末を防ぐために、最善を尽くしただけですから。","ENG":"That woman did what she could in her own way to stop the end from coming.","TWN":"她也只是在用自己的方式盡力阻止世界末日的到來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하다못해, 자신이 가장 아끼는 동생에겐 선량하고 헌신적인 누이로 남게 해줘야겠죠.","JPN":"せめて自分が一番愛しむ妹には善良で献身的な姉として居させてあげなくては。","ENG":"We should at least let her be a kind and devoted woman in her beloved younger sister's mind.","TWN":"至少讓她以一個善良無私的姊姊形象留在她妹妹心中吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"적어도 자신이 소중하게 생각하는 사람에겐 아름다운 모습으로 남고 싶다라…","JPN":"少なくとも自分が大切に思う人には美しい姿のままでいたい、か……","ENG":"Wanting to remain as a beautiful memory to her beloved...","TWN":"以美好的形象留在自己重視的人心中……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그건 결국 지휘자님이 예하께 바라던 것 아닌가요?","JPN":"それは結局指揮者様が猊下に望んでいたことじゃない？","ENG":"Isn't that what you wished from Her Eminence, Chief Conductor?","TWN":"那不是指揮家對主教的期望嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"똑같은 죄인에게 자신을 투영하는 꼴이 제법 추하시네요.","JPN":"同じ罪人に自分を投影するとは、なんて無様なの。","ENG":"Projecting yourself to another sinner like yourself. Rather ugly, if you ask me.","TWN":"把自己投射到同為罪人的她身上，真是醜陋。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"후후, 그렇군요.","JPN":"ふふ、そうですね。","ENG":"Fu fuu, yes.","TWN":"呵呵，原來如此啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"죄인을 자처하는 저 역시… 소중한 사람에겐 제 추악한 면모를 드러내는 게 두려웠던 거예요.","JPN":"罪人を名乗る私も同じく……大切な人に自分の醜い部分をさらすのが怖かったのです。","ENG":"As a sinner... I, too, was afraid of revealing my ugly side to the one I cherished.","TWN":"儘管我以罪人自居……卻還是害怕在重視的人面前展現自己醜陋的一面。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 뭐죠?","JPN":"あなたはなんですか？","ENG":"Who are you?","TWN":"你是什麼人？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"왜 살아있는 존재가 여기에 있는 건가요?","JPN":"なぜここに生きている存在がいるのですか？","ENG":"How is a living being here?","TWN":"活著的存在怎麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"오랜만이네요, 타기리온.","JPN":"久しぶりです、タギリオン。","ENG":"Long time no see, Thagirion.","TWN":"好久不見，塔基里翁。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이렇게 만난 걸 보면, 저는 결국 당신과 다시 마주해야 할 운명인 거겠죠.","JPN":"こうして出会ったということは、私は結局あなたと再び会わなければならない運命だったようですね。","ENG":"Seeing how we met again, you and I were destined to face each other once more.","TWN":"看來我們的重逢是命中註定的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"네퀴… 티아…?","JPN":"ネキ……ティア……？","ENG":"Ne... quitia...?","TWN":"莉奎……蒂亞……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};